CREATE TYPE "RoleLevel" AS ENUM ('CONTRIBUTOR', 'MEMBER', 'ADMIN');
CREATE TYPE "ContentStatus" AS ENUM ('DRAFT', 'PENDING', 'APPROVED', 'REJECTED');
CREATE TYPE "ContributionType" AS ENUM ('MEMORY', 'EVIDENCE');
CREATE TYPE "MediaKind" AS ENUM ('IMAGE', 'VIDEO', 'AUDIO', 'DOCUMENT');
CREATE TYPE "FieldType" AS ENUM ('SHORT_TEXT', 'LONG_TEXT', 'EMAIL', 'SINGLE_CHOICE', 'MULTIPLE_CHOICE', 'ATTACHMENT');

CREATE TABLE "Role" ("id" TEXT NOT NULL, "name" TEXT NOT NULL, "level" "RoleLevel" NOT NULL, "description" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Role_pkey" PRIMARY KEY ("id"));
CREATE TABLE "User" ("id" TEXT NOT NULL, "email" TEXT NOT NULL, "name" TEXT NOT NULL, "passwordHash" TEXT NOT NULL, "roleId" TEXT NOT NULL, "suspended" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "User_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Session" ("id" TEXT NOT NULL, "tokenHash" TEXT NOT NULL, "userId" TEXT NOT NULL, "expiresAt" TIMESTAMP(3) NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "lastSeenAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "Session_pkey" PRIMARY KEY ("id"));
CREATE TABLE "PasswordResetToken" ("id" TEXT NOT NULL, "tokenHash" TEXT NOT NULL, "userId" TEXT NOT NULL, "expiresAt" TIMESTAMP(3) NOT NULL, "usedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "PasswordResetToken_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Category" ("id" TEXT NOT NULL, "name" TEXT NOT NULL, "slug" TEXT NOT NULL, "description" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Category_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Contribution" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "type" "ContributionType" NOT NULL, "body" TEXT NOT NULL, "externalLinks" TEXT[] DEFAULT ARRAY[]::TEXT[], "status" "ContentStatus" NOT NULL DEFAULT 'PENDING', "rejectionNote" TEXT, "authorId" TEXT NOT NULL, "reviewerId" TEXT, "categoryId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "publishedAt" TIMESTAMP(3), CONSTRAINT "Contribution_pkey" PRIMARY KEY ("id"));
CREATE TABLE "MediaFile" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "description" TEXT, "kind" "MediaKind" NOT NULL, "mimeType" TEXT NOT NULL, "sizeBytes" INTEGER NOT NULL, "storageKey" TEXT NOT NULL, "publicUrl" TEXT NOT NULL, "originalName" TEXT NOT NULL, "altText" TEXT, "authorId" TEXT NOT NULL, "contributionId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "MediaFile_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Article" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "outlet" TEXT NOT NULL, "authorName" TEXT, "publishedOn" TIMESTAMP(3) NOT NULL, "url" TEXT NOT NULL, "summary" TEXT NOT NULL, "status" "ContentStatus" NOT NULL DEFAULT 'PENDING', "createdById" TEXT NOT NULL, "categoryId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Article_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Reflection" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "body" TEXT NOT NULL, "status" "ContentStatus" NOT NULL DEFAULT 'PENDING', "createdById" TEXT NOT NULL, "categoryId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, "publishedAt" TIMESTAMP(3), CONSTRAINT "Reflection_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Collection" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "description" TEXT NOT NULL, "published" BOOLEAN NOT NULL DEFAULT true, "createdById" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Collection_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CollectionItem" ("id" TEXT NOT NULL, "collectionId" TEXT NOT NULL, "contributionId" TEXT NOT NULL, "position" INTEGER NOT NULL DEFAULT 0, CONSTRAINT "CollectionItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CitizenForm" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "description" TEXT NOT NULL, "active" BOOLEAN NOT NULL DEFAULT true, "createdById" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "CitizenForm_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FormField" ("id" TEXT NOT NULL, "formId" TEXT NOT NULL, "label" TEXT NOT NULL, "type" "FieldType" NOT NULL, "required" BOOLEAN NOT NULL DEFAULT false, "options" TEXT[] DEFAULT ARRAY[]::TEXT[], "position" INTEGER NOT NULL DEFAULT 0, CONSTRAINT "FormField_pkey" PRIMARY KEY ("id"));
CREATE TABLE "FormResponse" ("id" TEXT NOT NULL, "formId" TEXT NOT NULL, "values" JSONB NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "FormResponse_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Survey" ("id" TEXT NOT NULL, "title" TEXT NOT NULL, "slug" TEXT NOT NULL, "question" TEXT NOT NULL, "resultsPublic" BOOLEAN NOT NULL DEFAULT true, "active" BOOLEAN NOT NULL DEFAULT true, "createdById" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "Survey_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SurveyOption" ("id" TEXT NOT NULL, "surveyId" TEXT NOT NULL, "label" TEXT NOT NULL, "position" INTEGER NOT NULL DEFAULT 0, CONSTRAINT "SurveyOption_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SurveyResponse" ("id" TEXT NOT NULL, "surveyId" TEXT NOT NULL, "optionId" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "ipHash" TEXT, CONSTRAINT "SurveyResponse_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SiteSetting" ("key" TEXT NOT NULL, "value" JSONB NOT NULL, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "SiteSetting_pkey" PRIMARY KEY ("key"));
CREATE TABLE "MenuItem" ("id" TEXT NOT NULL, "label" TEXT NOT NULL, "href" TEXT NOT NULL, "position" INTEGER NOT NULL DEFAULT 0, "visible" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "MenuItem_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AuditLog" ("id" TEXT NOT NULL, "actorId" TEXT, "action" TEXT NOT NULL, "entity" TEXT NOT NULL, "entityId" TEXT, "metadata" JSONB, "ipAddress" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "AuditLog_pkey" PRIMARY KEY ("id"));

CREATE UNIQUE INDEX "Role_name_key" ON "Role"("name");
CREATE UNIQUE INDEX "Role_level_key" ON "Role"("level");
CREATE UNIQUE INDEX "User_email_key" ON "User"("email");
CREATE UNIQUE INDEX "Session_tokenHash_key" ON "Session"("tokenHash");
CREATE UNIQUE INDEX "PasswordResetToken_tokenHash_key" ON "PasswordResetToken"("tokenHash");
CREATE UNIQUE INDEX "Category_name_key" ON "Category"("name");
CREATE UNIQUE INDEX "Category_slug_key" ON "Category"("slug");
CREATE UNIQUE INDEX "Contribution_slug_key" ON "Contribution"("slug");
CREATE UNIQUE INDEX "Article_slug_key" ON "Article"("slug");
CREATE UNIQUE INDEX "Reflection_slug_key" ON "Reflection"("slug");
CREATE UNIQUE INDEX "Collection_slug_key" ON "Collection"("slug");
CREATE UNIQUE INDEX "CollectionItem_collectionId_contributionId_key" ON "CollectionItem"("collectionId", "contributionId");
CREATE UNIQUE INDEX "CitizenForm_slug_key" ON "CitizenForm"("slug");
CREATE UNIQUE INDEX "Survey_slug_key" ON "Survey"("slug");

ALTER TABLE "User" ADD CONSTRAINT "User_roleId_fkey" FOREIGN KEY ("roleId") REFERENCES "Role"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "Session" ADD CONSTRAINT "Session_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE;
